WITH spend_total AS (
  SELECT SUM(spend) AS total_spend FROM marketing_spend WHERE spend_date BETWEEN {start_date} AND {end_date}
),
customer_total AS (
  SELECT COUNT(DISTINCT customer_id) AS new_customers FROM orders WHERE order_date BETWEEN {start_date} AND {end_date} AND order_sequence = 1
)
SELECT COALESCE(st.total_spend, 0) AS spend, COALESCE(ct.new_customers, 0) AS customers, COALESCE(st.total_spend, 0) / NULLIF(COALESCE(ct.new_customers, 0), 0) AS blended_cac FROM spend_total st, customer_total ct
